mapper.select:
SELECT id, user_id, name, start_date, billing_cycle, amount, created_at, updated_at, deleted_at
FROM   subscriptions
WHERE  id         = #{id}
  AND  user_id    = #{userId}
  AND  deleted_at IS NULL
LIMIT  1

mapper.update:
UPDATE subscriptions
SET    deleted_at = NOW()
WHERE  id         = #{id}
  AND  user_id    = #{userId}
  AND  deleted_at IS NULL
